const solve = (points, target) => {
    // Helper function to convert a point array [x, y, z] to a unique string key
    const pointToKey = (p) => `${p[0]},${p[1]},${p[2]}`;

    // Helper function to convert a key string back to a point array [x, y, z]
    const keyToPoint = (key) => {
        const parts = key.split(',').map(Number);
        return parts;
    };

    const targetKey = pointToKey(target);

    // --- Initialization (k=0) ---
    // P_set stores all unique points found so far, represented by their string keys.
    const P_set = new Set();
    for (const p of points) {
        const key = pointToKey(p);
        P_set.add(key);
    }

    if (P_set.has(targetKey)) {
        return 0;
    }

    // --- Iterative Generation (k=1, 2, ...) ---
    let k = 0;
    while (true) {
        k++;

        // Convert the current set of unique points to an array for easy iteration over pairs
        const P_array = Array.from(P_set).map(keyToPoint);
        const N = P_array.length;

        if (N < 2) {
            // Cannot form any new pairs if there are 0 or 1 points
            return -1;
        }

        const P_new_keys = new Set();
        let targetFoundInThisStep = false;

        // Generate new points by pairing every two distinct points
        // Iterate over unordered pairs (i, j) where i < j
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = P_array[i];
                const p2 = P_array[j];

                // Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cKey = pointToKey(c);

                // Check if this new point is the target
                if (cKey === targetKey) {
                    targetFoundInThisStep = true;
                    // We found it in generation k, no need to generate further in this step
                    // but we must break out of the inner loops and return k
                    break; 
                }

                // Add to the set of new points generated in this step
                P_new_keys.add(cKey);
            }
            if (targetFoundInThisStep) break;
        }

        if (targetFoundInThisStep) {
            return k;
        }

        // Merge new points into the main set P_set
        let pointsAdded = 0;
        for (const newKey of P_new_keys) {
            if (!P_set.has(newKey)) {
                P_set.add(newKey);
                pointsAdded++;
            }
        }

        // Termination condition: If no new unique points were generated, we are stuck.
        if (pointsAdded === 0) {
            return -1;
        }
    }
};

